{
  "verses": [
    {
      "n": 15,
      "column": "left",
      "text": "Un wiꞥſch mette Bultas/\\nn iſkaifija tohs/ wiꞥſch mette\\nSibbinus/ un fatreeze tohs."
    },
    {
      "n": 16,
      "column": "left",
      "text": "Tahs Juhras Dſelmes\\nrakdtjahs/ tahs Pafaules Dib-\\nbexi tappa atklahti no ta KUN-\\nGA Lammaschanae/ no Pu-\\ntchanas tahs Dwaschas winna\\nNahschu."
    },
    {
      "n": 17,
      "column": "left",
      "text": "Wiꞥſch fuhtija no tahs\\nAngſtibas/ un nehine manni/\\nwiꞥſch uſwilke mann no leelem\\nUhdenim."
    },
    {
      "n": 18,
      "column": "left",
      "text": "Wiꞥſchatpeſtija mann no\\nmanna ſtipra Eenatneeka / un\\nno manneem Mihdetajeem/ ka tee\\njo warrent bija/ ne ka eß."
    },
    {
      "n": 19,
      "column": "left",
      "text": "Kas manni pahrwarreja\\nmannu Behou Laika/ bet tas\\nKUNGS bija mans Pa-\\ntwerums."
    },
    {
      "n": 20,
      "column": "left",
      "text": "Wiꞥſch iſtwedde mann\\nPlattuna/ wiꞥſch iſrahweman-\\nni/ jo winnam bija labs Prahts\\npee mannts."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Tas KUNGS atmaffa\\nman pehz mannas Taiſutbas/\\nwiꞥſch makfa man pehz manno\\nRohku Schkihſtibas."
    },
    {
      "n": 22,
      "column": "left",
      "text": "Jo es efina ta KUNGA\\nZeltus ſargajs/ un ne efina beß-\\ndeewigt turrejees prett mannu\\nDeewu."
    },
    {
      "n": 23,
      "column": "left",
      "text": "Jo wiﬀas winna Teefas\\nfr manna Preekſcha/ un winna\\nEiſkumus es ne leeſu no mannim\\nnohſt."
    },
    {
      "n": 24,
      "column": "left",
      "text": "Bet es biju beswainigs\\npreekſch winna/ un ſargajohs no\\nmannas Noseedsibas."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un tas KUNGS doh\\nman atkat pehz mannas Taiſni\\nbas/ pehz mannas Schkihſtibaæ\\npreekſch winna Azziu."
    },
    {
      "n": 26,
      "column": "right",
      "text": "Pee teem Swehteem eß\\ntu ſwehts/ un pee teem Sirdeſ\\nskaidreem eſti tu ſkadriß."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Pee teem Schkihſteem eß\\ntu ſchkihſts/ un pee teem Pahr\\nwehrtiteem eſti tu pahrwehrtihts"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Jo tu atpeſti tobs behdi\\ngus Landis/ un tawas Azziis ir\\nprett teem Greschneem/ ka tu toh\\npaſemino:"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Jo tn eſti mans Spihdeſ\\nlis ak KUNGS! un tas KUNG\\ndarra mannu Tumſibu gaifchu"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Jo ar tevt warru es Kar\\nrogus fadauiht/ ar mannu Dee\\nwu warru es pahr Muhyeen\\nlehſt."
    },
    {
      "n": 31,
      "column": "right",
      "text": "Ta STIPRA DEE\\nWA Zetſch irr beswainigs / ta\\nKUNGA Walloda irr ſcheihsta\\nwiꞥſch irr par preekſchturramahn\\nBrunnahm wiſſeem/ kas us win\\nn patanjahs."
    },
    {
      "n": 32,
      "column": "right",
      "text": "Jo kur irr kahds Deews,\\nka ween tas KUNGS? un ku\\nnuhſu Deews?"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Tas STIPRAJE\\nDEEWS irr mans Stiprumi\\nn Spehks/ un irr mannu Zelfu\\ntattni lihdſinajs."
    },
    {
      "n": 34,
      "column": "right",
      "text": "Wiꞥſch darra manna\\nKahjas lihdsas tahin Erschku\\nMahtehm/ un eezeſt mann u\\nmanneem Augſtumeem."
    },
    {
      "n": 35,
      "column": "right",
      "text": "Wiꞥſch mahza manni\\nRohfu"
    }
  ],
  "confidence": "high",
